import React from 'react';
import { Link } from 'react-router-dom';

const Home = () => {
  return (
    <div className="pt-20">
      <section className="bg-gradient-to-r from-blue-700 to-blue-900 text-white py-24 px-4 text-center">
        <h1 className="text-5xl font-bold mb-6">Innovative Staffing & Software Solutions</h1>
        <p className="text-xl mb-10 max-w-2xl mx-auto text-blue-100">
          Hudson Manpower connects world-class talent with leading industries across Electronics, Electrical, and Chemical sectors.
        </p>
        <Link to="/careers" className="bg-white text-blue-700 px-8 py-3 rounded-full font-bold hover:bg-blue-50 transition-all">
          Explore Careers
        </Link>
      </section>
    </div>
  );
};

export default Home;
